// Full BSSN algebra naive CUDA kernel — the right-SCALE wall-B baseline.
//
// Runs the transliterated 850-statement CSE (_bssn_algebra_kernel.cuh, generated by
// gen_algebra_cuda.py) one thread per point, and reports the register/spill ptxas
// produces at FULL scale (the whole co-resident working set, not a single tensor) plus
// correctness vs the JAX verbatim oracle. This is the baseline any wall-B fix
// (warp-cooperative, array-restructuring, ...) must beat.
//
// Read first:  -Xptxas -v  "spill stores/loads" (true register spill) AND the runtime
// spill(local) = localSizeBytes (stack + spill + big local arrays). If this naive full
// algebra spills hard in nvcc the way it did in Triton/Pallas -> wall B is real in CUDA
// and a fix is motivated. If ptxas keeps it tame -> the spill was a Triton artifact.
//
// Build/run: see build.sh / README. Needs algebra_vectors.bin from gen_algebra_cuda.py.

#include <cstdio>
#include <cstdint>
#include <cstdlib>
#include <cmath>
#include <vector>
#include <cuda_runtime.h>

#include "_bssn_algebra_kernel.cuh"   // NF, ND, NOUT, NSCAL, __global__ bssn_algebra

#define CK(call) do { cudaError_t e = (call); if (e != cudaSuccess) { \
    fprintf(stderr, "CUDA error %s:%d: %s\n", __FILE__, __LINE__, \
            cudaGetErrorString(e)); std::exit(1); } } while (0)

static void report_attrs(const char* name, const void* kernel) {
    cudaFuncAttributes at; CK(cudaFuncGetAttributes(&at, kernel));
    // register-limited occupancy on Hopper (65536 regs/SM, 64 warps/SM max)
    int warps = at.numRegs > 0 ? 65536 / at.numRegs / 32 : 64;
    printf("   %-14s regs/thread = %3d   spill(local) = %5lld B   warps/SM(reg) = %2d "
           "(%2.0f%% occ)\n", name, at.numRegs, (long long)at.localSizeBytes,
           warps, 100.0 * warps / 64.0);
}

static bool read_block(FILE* f, std::vector<double>& v, size_t n) {
    v.resize(n);
    return fread(v.data(), sizeof(double), n, f) == n;
}

int main(int argc, char** argv) {
    const char* path = (argc > 1) ? argv[1] : "algebra_vectors.bin";
    FILE* f = fopen(path, "rb");
    if (!f) { fprintf(stderr, "cannot open %s (run gen_algebra_cuda.py)\n", path); return 1; }
    int64_t npts = 0;
    if (fread(&npts, sizeof(int64_t), 1, f) != 1) { fprintf(stderr, "bad header\n"); return 1; }
    std::vector<double> S, F, D, expected;
    if (!read_block(f, S, NSCAL) || !read_block(f, F, (size_t)NF * npts) ||
        !read_block(f, D, (size_t)ND * npts) || !read_block(f, expected, (size_t)NOUT * npts)) {
        fprintf(stderr, "bad body\n"); return 1;
    }
    fclose(f);
    printf(">> microbench_algebra | %lld points | fp64 | full CSE (NF=%d ND=%d NOUT=%d)\n",
           (long long)npts, NF, ND, NOUT);

    double *dF, *dD, *dS, *dOUT;
    CK(cudaMalloc(&dF, F.size() * sizeof(double)));
    CK(cudaMalloc(&dD, D.size() * sizeof(double)));
    CK(cudaMalloc(&dS, S.size() * sizeof(double)));
    CK(cudaMalloc(&dOUT, expected.size() * sizeof(double)));
    CK(cudaMemcpy(dF, F.data(), F.size() * sizeof(double), cudaMemcpyHostToDevice));
    CK(cudaMemcpy(dD, D.data(), D.size() * sizeof(double), cudaMemcpyHostToDevice));
    CK(cudaMemcpy(dS, S.data(), S.size() * sizeof(double), cudaMemcpyHostToDevice));

    printf(">> kernel attributes (the wall-B register/spill at full scale):\n");
    report_attrs("naive algebra", (const void*)bssn_algebra);

    int threads = 128;
    int blocks = (int)((npts + threads - 1) / threads);
    CK(cudaMemset(dOUT, 0, expected.size() * sizeof(double)));
    bssn_algebra<<<blocks, threads>>>(dF, dD, dS, dOUT, (int)npts);
    CK(cudaDeviceSynchronize());
    std::vector<double> host(expected.size());
    CK(cudaMemcpy(host.data(), dOUT, host.size() * sizeof(double), cudaMemcpyDeviceToHost));
    double abserr = 0.0, relerr = 0.0;
    for (size_t i = 0; i < expected.size(); ++i) {
        double e = fabs(host[i] - expected[i]);
        abserr = fmax(abserr, e);
        relerr = fmax(relerr, e / (fabs(expected[i]) + 1e-30));
    }

    const int iters = 200;
    cudaEvent_t a, b; CK(cudaEventCreate(&a)); CK(cudaEventCreate(&b));
    CK(cudaEventRecord(a));
    for (int it = 0; it < iters; ++it)
        bssn_algebra<<<blocks, threads>>>(dF, dD, dS, dOUT, (int)npts);
    CK(cudaEventRecord(b)); CK(cudaEventSynchronize(b));
    float ms = 0; CK(cudaEventElapsedTime(&ms, a, b));

    printf(">> correctness vs JAX oracle: max|abs| = %.2e   max|rel| = %.2e\n", abserr, relerr);
    printf(">> time = %.4f ms/launch (%lld points, algebra only — derivs are inputs)\n",
           ms / iters, (long long)npts);
    printf(">> GO/NO-GO: does the FULL algebra spill in ptxas (\"spill stores/loads\" > 0,\n"
           "   large local) as it did in Triton? That is the wall B a fix must beat.\n");

    CK(cudaFree(dF)); CK(cudaFree(dD)); CK(cudaFree(dS)); CK(cudaFree(dOUT));
    return 0;
}
